const BACKEND_BASE = 'https://ai.neberg.de';
function normalizeWebhookBody(body) {
  const b = body ?? {};
  return {
    threadId: b.threadId ?? b.ThreadId ?? '',
    chatHistory: b.chatHistory ?? b.History ?? b.history ?? [],
    userVision: b.userVision ?? b.UserVision ?? '',
  };
}
function buildLeoPrompt({ userVision, chatHistory }) {
  return [
    'You are Leo, AAE CEO orchestrator. Output ONLY JSON.',
    'Decompose the vision into supervisor-level delegations (or helga hr_request).',
    'Never use the word teamleiter; use supervisor-* agent ids.',
    'Schema: {"delegations":[{"targetAgentId":"supervisor-...|helga","intent":"delegation|hr_request","message":"...","moduleScope":"Module.X"}]}',
    `Vision: ${userVision}`,
    `History: ${JSON.stringify(chatHistory ?? [])}`,
  ].join('\n');
}
const raw = items[0].json.body ?? items[0].json;
const n = normalizeWebhookBody(raw);
return [{
  json: {
    ...n,
    prompt: buildLeoPrompt(n),
    BACKEND_BASE,
  }
}];

function parseJsonMaybe(text) {
  if (text == null) return null;
  if (typeof text === 'object') return text;
  const raw = String(text).trim();
  const fenced = raw.match(/```(?:json)?\s*([\s\S]*?)```/i);
  const candidate = fenced ? fenced[1].trim() : raw;
  try { return JSON.parse(candidate); } catch { return null; }
}
function assertNoTeamleiter(id) {
  return !String(id).toLowerCase().includes('teamleiter');
}
function parseLeoDelegations(agentOutput, threadId) {
  const obj = parseJsonMaybe(agentOutput);
  if (!obj || !Array.isArray(obj.delegations) || obj.delegations.length === 0) {
    return { ok: false, error: 'invalid_leo_output', userMessage: 'Leo could not produce valid delegations.' };
  }
  const itemsOut = [];
  for (const d of obj.delegations) {
    if (!d?.targetAgentId || !assertNoTeamleiter(d.targetAgentId)) {
      return { ok: false, error: 'invalid_target', userMessage: 'Leo produced an invalid targetAgentId.' };
    }
    const scope = d.moduleScope ? ` [scope=${d.moduleScope}]` : '';
    const intent = d.intent ? ` (${d.intent})` : '';
    itemsOut.push({
      threadId,
      senderAgentId: 'leo',
      targetAgentId: d.targetAgentId,
      content: `${d.message ?? ''}${intent}${scope}`.trim(),
    });
  }
  return { ok: true, items: itemsOut };
}
function buildFailureRoute({ threadId, senderAgentId, content }) {
  return { threadId, senderAgentId, targetAgentId: 'User', content };
}
const prev = $('Normalize Input').first().json;
const agentItem = items[0].json;
const agentText = agentItem.output ?? agentItem.text ?? agentItem;
const parsed = parseLeoDelegations(agentText, prev.threadId);
if (!parsed.ok) {
  return [{ json: { ok: false, routeBody: buildFailureRoute({ threadId: prev.threadId, senderAgentId: 'leo', content: parsed.userMessage }) } }];
}
return [{ json: { ok: true, items: parsed.items } }];
